+fn padded_readback_bytes_per_row(width: u32) -> u32 {
+    let unpadded = width.saturating_mul(4);
+    let alignment = wgpu::COPY_BYTES_PER_ROW_ALIGNMENT;
+    if unpadded == 0 {
+        0
+    } else {
+        unpadded.div_ceil(alignment) * alignment
+    }
+}
